#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int max = A[0];
        for (int i = 1; i < N; i++) {
            if (A[i] > max) {
                max = A[i];
            }
        }
        int total = 0;
        for (int i = 0; i < N; i++) {
            total += max - A[i];
        }
        if (total == M) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

